DEFAULT_HEADERS = {
    "User-Agent": (
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
        "AppleWebKit/537.36 (KHTML, like Gecko) "
        "Chrome/122.0 Safari/537.36"
    ),
    "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
    "Accept-Language": "fr-FR,fr;q=0.9,en;q=0.8",
    "Referer": "https://www.scimagojr.com/",
    "Connection": "keep-alive",
}

def parse_categories_from_html(html: str) -> pd.DataFrame:
    """
    Extrait (Code, Category) depuis le HTML Scimago et retourne un DataFrame.
    """
    pattern = re.compile(r"data-code='(\d+)'>([^<]+)</a>")
    matches = pattern.findall(html)
    df = pd.DataFrame(matches, columns=["Code", "Category"])
    return df


def download_csv_with_retry(category_id, temp_dir=TEMP_DIR, max_retries=3, delay=5, timeout=30):
    os.makedirs(temp_dir, exist_ok=True)
    file_name = os.path.join(temp_dir, f"journals_{category_id}.csv")
    url = f"https://www.scimagojr.com/journalrank.php?category={category_id}&out=xls"

    last_err = None
    for attempt in range(1, max_retries + 1):
        try:
            req = urllib.request.Request(url, headers=DEFAULT_HEADERS, method="GET")
            with urllib.request.urlopen(req, timeout=timeout) as resp:
                if resp.status != 200:
                    raise urllib.error.HTTPError(url, resp.status, resp.reason, resp.headers, None)
                data = resp.read()

            # sanity check rapide (parfois on reçoit une page HTML de blocage)
            if data[:200].lstrip().lower().startswith(b"<!doctype html") or b"<html" in data[:500].lower():
                raise RuntimeError("Réponse HTML reçue au lieu du fichier (probable blocage).")

            with open(file_name, "wb") as f:
                f.write(data)

            print(f"[Scimago] Fichier téléchargé : {file_name}")
            return file_name

        except Exception as e:
            last_err = e
            sleep_s = delay * attempt + random.uniform(0, 1.5)  # backoff + jitter
            print(f"[Scimago] Tentative {attempt} échouée ({e}), pause {sleep_s:.1f}s")
            time.sleep(sleep_s)

    print(f"[Scimago] Échec du téléchargement après plusieurs tentatives. Dernière erreur: {last_err}")
    return None


def extract_issns_and_names(file_name: str):
    df = pd.read_csv(file_name, sep=';', dtype=str)

    if 'Issn' not in df.columns or 'Title' not in df.columns:
        raise ValueError(f"Colonnes 'Issn' ou 'Title' absentes dans {file_name}")

    issns = df['Issn'].fillna("")
    titles = df['Title'].fillna("")

    res = []
    for issn_list, title in zip(issns, titles):
        for issn in issn_list.split(','):
            issn = issn.strip()
            if issn and issn != '-':
                res.append((issn, title.strip()))
    return res


def get_issns_for_categories(categories_to_keep) -> pd.DataFrame:
    """
    Étape complète :
      - parse le HTML Scimago
      - filtre les catégories souhaitées
      - télécharge les CSV de journaux
      - extrait tous les ISSN + noms de journaux
      - retourne un DataFrame sans doublons : colonnes ['issn', 'journal']
    """
    df_cats = parse_categories_from_html(HTML_CATEGORIES)
    df_sel = df_cats[df_cats["Category"].isin(categories_to_keep)]

    all_issns_and_titles = []

    for _, row in df_sel.iterrows():
        category_id = row["Code"]
        category_name = row["Category"]

        file_name = download_csv_with_retry(category_id)
        if not file_name:
            continue

        try:
            issns_titles = extract_issns_and_names(file_name)
            all_issns_and_titles.extend(issns_titles)
        except Exception as e:
            print(f"[Scimago] Erreur extraction ISSN pour {category_name}: {e}")
        finally:
            try:
                os.remove(file_name)
            except OSError:
                pass

    # dédoublonnage
    unique = {}
    for issn, title in all_issns_and_titles:
        if issn not in unique:
            unique[issn] = title

    df_issn = pd.DataFrame(
        [(k, v) for k, v in unique.items()],
        columns=["issn", "journal"]
    )

    return df_issn
